                    // 2. Mengganti thumbnail dengan iframe
                    container.innerHTML = ''; // Hapus konten lama (thumbnail)
                    container.appendChild(iframe); // Tambahkan iframe
                });
            }
        });

        // Onboarding
        let currentActiveStep = 1;

        function changeOnboardingImage(step) {
            const stepNumber = parseInt(step.replace('step', ''));
            currentActiveStep = stepNumber;

            const imagePaths = {
                step1: "https://englishvit.com/image_assets/ieltsai/register-69367238decf1.webp",
                step2: "https://englishvit.com/image_assets/ieltsai/2-langsung-tes-6937db76eb6c9.webp",
                step3: "https://englishvit.com/image_assets/ieltsai/3-lihat-hasil-dan-feedback-6937db76ab732.webp",
            };

            const defaultImages = {
                desktop: "https://englishvit.com/image_assets/ieltsai/register-69367238decf1.webp",
                mobile: "https://englishvit.com/image_assets/onboarding-steps/onboarding-step-new.webp"
            };

            // Update desktop image
            const desktopImage = document.getElementById('onboarding-image');
            if (desktopImage) {
                desktopImage.style.opacity = '0';
                setTimeout(() => {
                    desktopImage.src = imagePaths[step] || defaultImages.desktop;
                    desktopImage.style.opacity = '1';
                }, 150);
            }

            // Update mobile image
            const mobileImage = document.getElementById('mobile-onboarding-image');
            if (mobileImage) {
                mobileImage.style.opacity = '0';
                setTimeout(() => {
                    mobileImage.src = imagePaths[step] || defaultImages.mobile;
                    mobileImage.style.opacity = '1';
                }, 150);
            }

            // Update active states
            updateActiveStates(stepNumber);
        }

        function updateActiveStates(activeStep) {
            // Update desktop steps
            for (let i = 1; i <= 3; i++) {
                const isActive = i === activeStep;

                // Desktop icons
                const desktopIcon = document.getElementById(`desktop-step${i}`);
                if (desktopIcon) {
                    desktopIcon.style.backgroundColor = isActive ? '#155DFC' : '#D4D4D4';
                }

                // Tablet icons
                const tabletIcon = document.getElementById(`tablet-step${i}`);
                if (tabletIcon) {
                    tabletIcon.style.backgroundColor = isActive ? '#155DFC' : '#D4D4D4';
                }

                // Mobile icons
                const mobileIcon = document.getElementById(`mobile-step${i}`);
                if (mobileIcon) {
                    mobileIcon.style.backgroundColor = isActive ? '#155DFC' : '#D4D4D4';
                }

                // Text colors
                const stepElement = document.querySelector(`[data-step="${i}"]`);
                if (stepElement) {
                    const heading = stepElement.querySelector('h3');
                    const paragraph = stepElement.querySelector('p');

                    if (heading) {
                        heading.style.color = isActive ? '#262626' : '#A1A1A1';
                    }
                    if (paragraph) {
                        paragraph.style.color = isActive ? '#525252' : '#A1A1A1';
                    }

                    // Update active class
                    if (isActive) {
                        stepElement.classList.add('active-step');
                    } else {
                        stepElement.classList.remove('active-step');
                    }
                }
            }
        }

        // Initialize with step 1 active
        document.addEventListener('DOMContentLoaded', function() {
            updateActiveStates(1);
        });

        // Credibility section
        document.addEventListener('DOMContentLoaded', function() {
            // Inisialisasi Swiper JS untuk Credibility Section
            const credibilitySwiper = new Swiper('.credibility-swiper', {
                // Default mobile view (1 slide penuh)
                slidesPerView: 1,
                spaceBetween: 0,
                loop: true,

                // Pagination
                pagination: {
                    el: '.credibility-pagination',
                    clickable: true,
                },

                // Konfigurasi Responsive
                breakpoints: {
                    768: { // Tablet view
                        slidesPerView: 1,
                        spaceBetween: 0,
                    },
                    1024: { // Desktop view
                        slidesPerView: 3,
                        spaceBetween: 24,
                        loop: false,
                        autoplay: false
                    },
                },
            });
        });

        // FAQ section
        document.addEventListener('DOMContentLoaded', function() {
            // Data pertanyaan dan jawaban untuk SEMUA tab
            const faqData = {
                'umum': [{
                        q: "AI-nya beneran bisa kasih feedback akurat gak?",
                        a: "AI kami dikembangkan berdasarkan rubrik resmi IELTS. Feedback mencakup 4 aspek utama persis seperti penilai asli. Bahkan banyak pengguna bilang skornya mirip saat tes resmi."
                    },
                    {
                        q: "Takut uangnya nggak worth it?",
                        a: "Mulai dari Rp49.000 lebih murah dari 1 sesi privat. Kalau tidak bisa akses? Uang kembali."
                    },
                    {
                        q: "Lebih percaya latihan sama tutor langsung.",
                        a: "AI gak pernah capek. Kamu bisa latihan kapan aja, sebanyak apa pun, dan hasilnya selalu objektif."
                    }
                ],
                'speaking': [{
                        q: "Apa saja yang dinilai di Speaking?",
                        a: "Berdasarkan rubrik penilaian IELTS resmi, Speaking kamu dinilai dari kelancaran kamu dalam berbicara, kosakata dan grammar yang kamu pakai, serta pelafalan kamu."
                    },
                    {
                        q: "Apakah pertanyaan Speaking yang digunakan sama dengan tes IELTS asli?",
                        a: "Ya! Kita menggunakan pertanyaan dari IELTS question bank official dan database pertanyaan yang sering muncul di tes real."
                    },
                    {
                        q: "Bisa latihan Speaking dengan accent Indonesia? ",
                        a: "Bisa banget dengan accent Indonesia! IELTS ga menuntut native accent. Yang penting pronunciation jelas dan bisa dipahami."
                    }
                ],
                'writing': [{
                        q: "Writing AI beneran bisa bikin manajemen waktu jadi lebih gampang?",
                        a: "Timer Writing kita dirancang berdasarkan strategi time management yang terbukti efektif dalam IELTS Writing. Kamu akan selalu diingetin: kapan mulai, mikirin ide, bikin plan, lanjut nulis, dan revisi tulisan kamu."
                    },
                    {
                        q: "Apakah feedback Writing dari AI bisa dipercaya?",
                        a: "Ya! AI kita bisa deteksi kesalahan grammar dan vocabulary secara akurat dan mendetail. Tulisan kamu juga dinilai pakai rubrik Official IELTS, lengkap dengan rekomendasi biar writing kamu setara band 8+."
                    },
                    {
                        q: "Apakah topik Writing yang dipakai sesuai dengan tes IELTS terbaru?",
                        a: "Pastinya! Soal Writing di database kita diambil dari tes IELTS asli dan selalu up-to-date mengikuti tren IELTS terbaru. "
                    }
                ]
            };

            const tabButtons = document.querySelectorAll('.tab-button');
            const faqContent = document.getElementById('faq-content');

            // Konstanta Warna & Padding
            const activeTabColor = '#155DFC';
            const activeTabBg = '#EFF6FF';
            const inactiveTabColor = '#6b7280';
            const activeFaqQColor = '#155DFC';
            const inactiveFaqQColor = '#404040';
            const answerTextColor = '#737373';
            // const answerPaddingBottomActive = '1rem'; 
            // const answerPaddingTopActive = '0.5rem'; 
            const questionPaddingBottom = '0.5rem';

            // Fungsi untuk mengatur styling tab aktif (termasuk radius)
            function setActiveTabStyle(button) {
                // Reset semua tab
                tabButtons.forEach(btn => {
                    btn.classList.remove('active');
                    btn.classList.remove('tab-radius-left', 'tab-radius-right');
                    btn.style.color = inactiveTabColor;
                    btn.style.backgroundColor = 'transparent';
                });

                // Terapkan styling active
                button.classList.add('active');
                button.style.color = activeTabColor;
                button.style.backgroundColor = activeTabBg;

                // Terapkan radius
                const tabName = button.getAttribute('data-tab');
                if (tabName === 'umum') {
                    button.classList.add('tab-radius-left');
                } else if (tabName === 'writing') {
                    button.classList.add('tab-radius-right');
                }
            }

            // Ganti Konten FAQ
            function renderFaq(tabName, activateFirst = false) {
                faqContent.innerHTML = '';
                const data = faqData[tabName];

                data.forEach((item, index) => {
                    const isActive = activateFirst && index === 0;

                    const faqItem = document.createElement('div');
                    faqItem.className = `faq-item transition-all duration-300 ${isActive ? 'active-faq' : ''}`;

                    const questionColor = isActive ? activeFaqQColor : inactiveFaqQColor;

                    faqItem.innerHTML = `
                        <button class="question-button font-semibold w-full px-4 py-3 text-left flex justify-between items-start" style="color: ${questionColor}; padding-bottom: ${questionPaddingBottom};">
                            ${item.q}
                            <svg class="w-5 h-5 transition-transform duration-300 transform${isActive ? ' rotate-180' : ''} flex-shrink-0 mt-1" fill="none" stroke="currentColor" viewBox="0 0 24 24" xmlns="http://www.w3.org/2000/svg"><path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M19 9l-7 7-7-7"></path></svg>
                        </button>
                        <div class="answer-content px-4 overflow-hidden text-left" style="max-height: 0;">
                            <p class="text-sm leading-relaxed" style="color: ${answerTextColor};">
                                ${item.a}
                            </p>
                        </div>
                    `;
                    faqContent.appendChild(faqItem);

                    // Mengatur inisialisasi item pertama
                    if (isActive) {
                        const answer = faqItem.querySelector('.answer-content');
                        setTimeout(() => {
                            answer.style.maxHeight = answer.scrollHeight + 30 + 'px';
                            // answer.style.paddingTop = answerPaddingTopActive;
                            // answer.style.paddingBottom = answerPaddingBottomActive; 
                        }, 100);
                    }
                });

                addAccordionListeners();
            }

            // Atur Fungsi Accordion (Logic klik untuk buka/tutup)
            function addAccordionListeners() {
                const questionButtons = faqContent.querySelectorAll('.question-button');

                questionButtons.forEach(button => {
                    button.addEventListener('click', function() {
                        const parentItem = this.closest('.faq-item');
                        const answer = parentItem.querySelector('.answer-content');
                        const svg = parentItem.querySelector('svg');
                        const isActive = parentItem.classList.contains('active-faq');

                        // Tutup semua FAQ dan reset styling
                        faqContent.querySelectorAll('.faq-item').forEach(item => {
                            item.classList.remove('active-faq');
                            item.querySelector('.question-button').style.color = inactiveFaqQColor;
                            item.querySelector('.answer-content').style.maxHeight = '0';
                            item.querySelector('.answer-content').style.paddingTop = '0';
                            item.querySelector('.answer-content').style.paddingBottom = '0';
                            item.querySelector('svg').classList.remove('rotate-180');
                        });

                        // Buka atau tutup item yang diklik
                        if (!isActive) {
                            parentItem.classList.add('active-faq');
                            this.style.color = activeFaqQColor;
                            answer.style.maxHeight = answer.scrollHeight + 30 + 'px';
                            // answer.style.paddingTop = answerPaddingTopActive;
                            // answer.style.paddingBottom = answerPaddingBottomActive; 
                            svg.classList.add('rotate-180');
                        }
                    });
                });
            }

            // Event Listener untuk Tab Buttons - FAQ
            tabButtons.forEach(button => {
                button.addEventListener('click', function() {
                    const tabName = this.getAttribute('data-tab');

                    // 1. Update Tab Styling
                    setActiveTabStyle(this);

                    // 2. Render Konten
                    renderFaq(tabName, true);
                });
            });

            // Inisialisasi: Set tab awal dan render konten FAQ
            const initialTab = document.querySelector('.tab-button[data-tab="umum"]');

            if (initialTab) {
                setActiveTabStyle(initialTab);
            }

            renderFaq('umum', true);
        });

        // Animasi
        document.addEventListener('DOMContentLoaded', function() {
            const sections = document.querySelectorAll('.animate-section');

            const observerOptions = {
                root: null,
                rootMargin: '0px',
                threshold: 0.15
            };

            const observer = new IntersectionObserver((entries) => {
                entries.forEach(entry => {
                    const animatedElements = entry.target.querySelectorAll('.animate-item');

                    if (entry.isIntersecting) {
